	ContextConstraint compileContextConstraint(StatementPattern sp, Dataset dataset) {
		if (dataset == null) {
			return ContextConstraint.UNRESTRICTED;
		}
		Set<IRI> graphs;
		boolean emptyGraph;
		if (sp.getScope() == Scope.DEFAULT_CONTEXTS) {
			graphs = dataset.getDefaultGraphs();
			emptyGraph = graphs.isEmpty() && !dataset.getNamedGraphs().isEmpty();
		} else {
			graphs = dataset.getNamedGraphs();
			emptyGraph = graphs.isEmpty() && !dataset.getDefaultGraphs().isEmpty();
		}
		if (emptyGraph) {
			return ContextConstraint.EMPTY;
		}
		if (graphs == null || graphs.isEmpty()) {
			return ContextConstraint.UNRESTRICTED;
		}
		long[] ids = new long[graphs.size()];
		int size = 0;
		for (IRI graph : graphs) {
			long id;
			if (RDF4J.NIL.equals(graph) || SESAME.NIL.equals(graph)) {
				id = NULL_CONTEXT_ID;
			} else {
				id = idOf(graph);
				if (id == UNKNOWN) {
					continue;
				}
			}
			ids[size++] = id;
		}
		return size == 0 ? ContextConstraint.EMPTY : new ContextConstraint(Arrays.copyOf(ids, size));
	}

	Term compileTerm(Var var, NativePatternField field) {
		if (var == null) {
			return Term.unbound();
		}
		if (var.hasValue()) {
			Value value = var.getValue();
			if (!validValueForField(value, field)) {
				return null;
			}
			if (field == NativePatternField.CONTEXT && isNullContextValue(value)) {
				return Term.constant(NULL_CONTEXT_ID);
			}
			long id = idOf(value);
			if (id == UNKNOWN) {
				return null;
			}
			if (var.isAnonymous()) {
				return Term.constant(id);
			}
			// a named var carrying an optimizer-assigned value (e.g. an inlined prepared-query binding)
			// must both constrain the scan and still emit the binding under its name, exactly like the
			// generic engine; compiling it as a bare constant would make the name invisible to filters
			// and drop it from result rows
			return Term.constantSlot(slot(var.getName()), id);
		}
		if (var.isConstant()) {
			return Term.unbound();
		}
		return Term.slot(slot(var.getName()));
	}

	int slot(String name) {
		Integer existing = slots.get(name);
		if (existing != null) {
			return existing;
		}
		int next = slots.size();
		slots.put(name, next);
		slotNames.add(name);
		return next;
	}

	int existingSlot(String name) {
		Integer existing = slots.get(name);
		return existing == null ? -1 : existing;
	}

	long idOf(Value value) {
		return source.idOf(value);
	}

